#requires -Version 5.1
<# Created by Dewald Pretorius. Validates case structure and evidence hashes without changing evidence. #>
[CmdletBinding()]param([Parameter(Mandatory=$true)][string]$CasePath,[string]$OutputPath=(Join-Path ([Environment]::GetFolderPath('Desktop')) 'IR_Case_Validation'))
$ErrorActionPreference='Stop';New-Item -ItemType Directory $OutputPath -Force|Out-Null;$s=Get-Date -Format yyyyMMdd_HHmmss
try{if(-not(Test-Path -LiteralPath $CasePath -PathType Container)){Write-Error 'CasePath was not found.';exit 3};$files=@(Get-ChildItem $CasePath -Recurse -File);$hashes=@($files|ForEach-Object{$h=Get-FileHash $_.FullName -Algorithm SHA256;[pscustomobject]@{RelativePath=$_.FullName.Substring((Resolve-Path $CasePath).Path.Length).TrimStart('\');Length=$_.Length;LastWriteTimeUtc=$_.LastWriteTimeUtc;SHA256=$h.Hash}});$required='Evidence','Notes','Timeline';$missing=@($required|Where-Object{-not(Test-Path (Join-Path $CasePath $_) -PathType Container)});$hashes|Export-Csv (Join-Path $OutputPath "evidence_manifest_$s.csv") -NoTypeInformation;[ordered]@{Generated=(Get-Date);CasePath=(Resolve-Path $CasePath).Path;FileCount=$hashes.Count;MissingFolders=$missing;Evidence=$hashes}|ConvertTo-Json -Depth 6|Set-Content (Join-Path $OutputPath "case_validation_$s.json");if($missing.Count-or$hashes.Count-eq0){exit 1};exit 0}catch{Write-Error $_;exit 5}
